  render: () => {
    const [selected, setSelected] = useState<string | null>(null);
    const slowFetch = (query: string) => new Promise<string[]>(resolve => {
      const q = query.toLowerCase();
      const filtered = COUNTRIES.filter(c => c.toLowerCase().includes(q));
      setTimeout(() => resolve(filtered), 800);
    });
    return <div>
        <Autocomplete<string> fetchSuggestions={slowFetch} getOptionLabel={opt => opt} onSelect={setSelected} placeholder="Slow search (800ms)..." debounceMs={400} />
        {selected && <p style={{
        marginTop: 12,
        fontSize: 14,
        color: "#666"
      }}>
            Selected: {selected}
          </p>}
      </div>;
  }
